    picture.lines().forEach { line ->
        pictureBuilder.append("$borderSymbol$separator")
        pictureBuilder.append(line)
        pictureBuilder.append(separator.toString().repeat(pictureWidth - line.length))
        pictureBuilder.append("$separator$borderSymbol")
        pictureBuilder.append(newLineSymbol)
    }
    pictureBuilder.append(horizontalBorder)

    return pictureBuilder.toString()
}

fun applySquaredFilter(picture: String): String {
    val borderedPicture = applyBordersFilter(picture)
    val pictureBuilder = StringBuilder("")

    borderedPicture.lines().forEach { line ->
        pictureBuilder.append(line + line + newLineSymbol)
    }
    pictureBuilder.removeSuffix("#")
    pictureBuilder.append(pictureBuilder.toString())

    return pictureBuilder.toString()
}

