fun trimPicture(picture: String): String = picture.trimIndent().trimMargin()

fun applyBordersFilter(picture: String): String {
    val pictureWidth = getPictureWidth(picture)
    val horizontalBorder = "#".repeat(pictureWidth + 4)
    val pictureBuilder = StringBuilder(horizontalBorder + newLineSymbol)

    picture.lines().forEach { line ->
        pictureBuilder.append("$borderSymbol$separator")
        pictureBuilder.append(line)
        pictureBuilder.append(separator.toString().repeat(pictureWidth - line.length))
        pictureBuilder.append("$separator$borderSymbol")
        pictureBuilder.append(newLineSymbol)
    }
    pictureBuilder.append(horizontalBorder)

    return pictureBuilder.toString()
}

fun applySquaredFilter(picture: String): String {
    val borderedPicture = applyBordersFilter(picture)

    return """
        $borderedPicture$borderedPicture$newLineSymbol
        $borderedPicture$borderedPicture
    """
}

fun applyFilter(picture: String, filter: String): String {
    val trimmedPicture = trimPicture(picture)
    return when (filter) {
        "borders" -> applyBordersFilter(trimmedPicture)
        "squared" -> applySquaredFilter(trimmedPicture)
        else -> error("Unexpected filter")
    }
}

package jetbrains.kotlin.course.warmup

import kotlin.math.max

// You will use this function later
fun getGameRules(wordLength: Int, maxAttemptsCount: Int, secretExample: String) =
    "Welcome to the game! $newLineSymbol" +
            newLineSymbol +
            "Two people play this game: one chooses a word (a sequence of letters), " +
            "the other guesses it. In this version, the computer chooses the word: " +
            "a sequence of $wordLength letters (for example, $secretExample). " +
            "The user has several attempts to guess it (the max number is $maxAttemptsCount). " +
            "For each attempt, the number of complete matches (letter and position) " +
            "and partial matches (letter only) is reported. $newLineSymbol" +
            newLineSymbol +
            "For example, with $secretExample as the hidden word, the BCDF guess will " +
            "give 1 full match (C) and 1 partial match (B)."

fun generateSecret() = "ABCD"
fun countPartialMatches(secret: String, guess: String): Int {
    val exactMatches = countExactMatches(secret, guess)
    val allMatches = countAllMatches(secret, guess)
    return allMatches - exactMatches
}

fun countAllMatches(secret: String, guess: String): Int {
    val secretCharCount = secret.groupBy { it }.mapValues { it.value.size }
    val guessCharCount = guess.groupBy { it }.mapValues { it.value.size }

    var allMatches = 0
    for ((char, count) in secretCharCount) {
        allMatches += minOf(count, guessCharCount.getOrDefault(char, 0))
    }
    return allMatches
}

fun countExactMatches(secret: String, guess: String): Int {
    require(secret.length == guess.length) { "Secret and guess must be of equal length" }
    var exactMatches = 0
    for (i in secret.indices) {
        if (secret[i] == guess[i]) {
            exactMatches++
        }
    }
    return exactMatches
}



fun playGame(secret: String, wordLength: Int, maxAttemptsCount: Int) {
    var complete: Boolean
    var attempts = 0 // Initialize attempts counter

    do {
        println("Please input your guess. It should be of length $wordLength.")
        val guess = safeReadLine()
        complete = isComplete(secret, guess)
        attempts++

        if (isWon(complete, attempts, maxAttemptsCount)) {
            println("Congratulations! You guessed it!")
            return
        } else if (isLost(complete, attempts, maxAttemptsCount)) {
            println("Sorry, you lost! :( My word is $secret")
            return
        }

    } while (!complete && attempts <= maxAttemptsCount)
}


fun isComplete(secret: String, guess: String) = if (secret == guess){
    true
} else{
    false
}

fun printRoundResults(secret: String, guess: String) {
    val exactMatches = countExactMatches(secret, guess)
    val partialMatches = countPartialMatches(secret, guess)

    println("Your guess has $exactMatches full matches and $partialMatches partial matches.")
}


fun isWon(complete: Boolean, attempts: Int, maxAttemptsCount: Int): Boolean {
    return complete && attempts <= maxAttemptsCount
}
fun isLost(complete: Boolean, attempts: Int, maxAttemptsCount: Int): Boolean {
    return !complete && attempts > maxAttemptsCount
}



fun main() {
    val wordLength = 4
    val maxAttemptsCount = 3
    val secretExample = "ACEB"
    println(getGameRules(wordLength, maxAttemptsCount, secretExample))

    val secret = generateSecret()
    playGame(secret, wordLength, maxAttemptsCount)

}

