// You will use this function later
fun isWon(complete: Boolean, attempts: Int, maxAttemptsCount: Int) = complete && attempts <= maxAttemptsCount

// You will use this function later
fun isLost(complete: Boolean, attempts: Int, maxAttemptsCount: Int) = !complete && attempts > maxAttemptsCount

fun isComplete(secretWord: String, currentGuess: String): Boolean {
    val current = currentGuess.replace(separator, "")
    return secretWord == current
}

fun generateNewUserWord(secretWord: String, guess: Char, currentUserWord: String): String {
    var result = ""

    for (i in secretWord.indices) {
        val letter = secretWord[i]
        result += if (guess == letter) {
            "$guess$separator"
        } else {
            "${currentUserWord[i * 2]}$separator"
        }
    }
    return result.removeSuffix(" ")
}

fun generateSecret(): String = words.random()

fun getHiddenSecret(wordLength: Int): String =
    List(wordLength) { "_" }.joinToString(" ")

fun isCorrectInput(userInput: String): Boolean {
    if (userInput.length != 1) {
        println("The length of your guess should be 1! Try again!")
        return false
    } else if (!userInput[0].isLetter()) {
        println("You should input only English letters! Try again!")
        return false
    }
    return true
}

fun safeUserInput(): Char {
    var guess: String
    do {
        println("Please input your guess.")
        guess = safeReadLine()

    } while (!isCorrectInput(guess))
    return guess.uppercase()[0]
}

fun getRoundResults(secretWord: String, guess: Char, currentUserWord: String): String {
    val newUserWord = generateNewUserWord(secretWord, guess, currentUserWord)
    if (guess !in secretWord) {
        println(
            "Sorry, the secret does not contain the symbol: $guess. " +
                    "The current word is $currentUserWord"
        )
    } else {
        println("Great! This letter is in the word! The current word is $newUserWord")
    }
    return newUserWord
}

fun playGame(secretWord: String, maxAttemptsCount: Int) {
    var complete: Boolean
    var attempts = maxAttemptsCount
    var currentUserWord = getHiddenSecret(secretWord.length)
    do {
        val guess = safeUserInput()
        currentUserWord = getRoundResults(secretWord, guess, currentUserWord)
        complete = isComplete(secretWord, currentUserWord)
        attempts--
        if (isLost(complete, attempts, maxAttemptsCount)) {
            println("Sorry, you lost!    My word is $secretWord")
            return
        } else if (isWon(complete, attempts, maxAttemptsCount)) {
            println("Congratulations! You guessed it!")
        }
    } while (!complete && attempts > 0)
}

fun main() {
    // Uncomment this code on the last step of the game

     println(getGameRules(wordLength, maxAttemptsCount))
     println(playGame(generateSecret(), maxAttemptsCount))
    //println(generateNewUserWord("BOOK", 'B', "_ O O _"))
}

