fun playGame(secret: String, maxAttemptsCount: Int) {
    var currentWord = getHiddenSecret(secret.length)
    var attempts = 0
    var complete = false

    println(getGameRules(secret.length, maxAttemptsCount))

    while (!complete && attempts < maxAttemptsCount) {
        val guess = safeUserInput()
        currentWord = getRoundResults(secret, guess, currentWord)
        attempts++
        complete = isComplete(secret, currentWord)
    }

    if (isWon(complete, attempts, maxAttemptsCount)) {
        println("Congratulations! You've guessed the word!")
    } else if (isLost(complete, attempts, maxAttemptsCount)) {
        println("Sorry, you've run out of attempts. The secret word was: $secret")
    }
