fun dropTopFromLine(line: String, width: Int, patternHeight: Int, patternWidth: Int): String {
    val rowLength = patternWidth + 1
    return if (patternHeight > 1) {
        line.drop(rowLength)
    } else {
        line
    }
}

fun canvasGenerator(pattern: String, width: Int, height: Int): String {
    val patternWidth = getPatternWidth(pattern)
    val patternHeight = getPatternHeight(pattern)
    val repeatedPattern = repeatHorizontally(pattern, width, patternWidth)
    if (height == 1) return repeatedPattern
    var canvas = repeatedPattern
    repeat(height - 1) {
        val repeatedWithDrop = dropTopFromLine(canvas, width, patternHeight, patternWidth)
        canvas += repeatedWithDrop
    }
    return canvas.removeSuffix(newLineSymbol)
}


