        "if it is in the hidden word, all matches will be guessed.$newLineSymbol$newLineSymbol" +
        "" +
        "For example, if the word \"CAT\" was guessed, \"_ _ _\" will be displayed first, " +
        "since the word has 3 letters.$newLineSymbol" +
        "If you enter the letter A, you will see \"_ A _\" and so on.$newLineSymbol$newLineSymbol" +
        "" +
        "Good luck in the game!"

// You will use this function later
fun isWon(complete: Boolean, attempts: Int, maxAttemptsCount: Int) = complete && attempts <= maxAttemptsCount

// You will use this function later
fun isLost(complete: Boolean, attempts: Int, maxAttemptsCount: Int) = !complete && attempts > maxAttemptsCount

fun isComplete(secret: String, currentGuess: String): Boolean = secret == currentGuess.filterNot { it == ' ' }


fun generateNewUserWord(secret: String, guess: Char, currentUserWord: String): String {
    val formattedSecret = secret.toList().joinToString { "" }
    val builder = StringBuilder("")

    formattedSecret.indices.forEach { i -> if (formattedSecret[i] == guess) builder.append("$guess ") }

    return builder.toString().removeSuffix(" ")
}

fun generateNewUserWord2(secret: String, guess: Char, currentUserWord: String): String {
    val builder = StringBuilder(currentUserWord.filterNot { it == ' ' })

    secret.indices.forEach { i -> if (secret[i] == guess) builder[i] = guess }

    return builder.toList().joinToString(" ")
}

fun generateNewUserWord3(secret: String, guess: Char, currentUserWord: String): String {
    var newUserWord = ""

    secret.indices.forEach { i ->
        if (secret[i] == guess) newUserWord += "${secret[i]} "
        else newUserWord += "${currentUserWord[i * 2]} "
    }

    return newUserWord.removeSuffix(" ")
}

