fun fillPatternRow(patternRow: String, patternWidth: Int): String {
    check(patternRow.length <= patternWidth) { "patternRow length exceeds patternWidth" }
    return patternRow + "$separator".repeat(patternWidth - patternRow.length)
}

fun repeatHorizontally(pattern: String, n: Int, patternWidth: Int): String {
    return if (patternWidth == 1) {
        pattern.repeat(n)
    } else {
        val filledPattern = pattern.lines().joinToString(newLineSymbol) { fillPatternRow(it, patternWidth) }

        filledPattern.split(newLineSymbol).joinToString(newLineSymbol) { row ->
            row.chunked(patternWidth).joinToString("$separator".repeat(n))
        }
    }
}

fun dropTopFromLine(line: String, width: Int, patternHeight: Int, patternWidth: Int): String {
    return if (patternHeight > 1) {
        val charsToDrop = patternWidth * width + newLineSymbol.length
        line.drop(charsToDrop)
    } else {
        line
    }
}

fun getPatternHeight(pattern: String): Int {
    val height = pattern.split('\n')
    return height.size
}

// You will use this function later
fun choosePattern(): String {
    do {
        println("Please choose a pattern. The possible options: ${allPatterns().joinToString(", ")}")
        val name = safeReadLine()
        val pattern = getPatternByName(name)
        pattern?.let {
            return@choosePattern pattern
        }
    } while (true)
}

fun canvasGenerator(pattern: String,width: Int,height: Int): String {
    val patternWidth = getPatternWidth(pattern)
    val patternHeight = getPatternHeight(pattern)
    val repeatedPattern = repeatHorizontally(pattern,width,patternWidth)
    val canvasRows = (1..height).map { Level ->
        val remainingHeight = patternHeight - (Level - 1)
        val levelPattern = if (remainingHeight > 1) {
            dropTopFromLine(repeatedPattern, width, remainingHeight, patternWidth)
        } else {
            repeatedPattern
        }
        levelPattern
    }
    return canvasRows.joinToString(newLineSymbol)
}

fun canvasWithGapsGenerator(pattern: String, width: Int, height: Int): String {
    val patternWidth = getPatternWidth(pattern)
    val patternHeight = getPatternHeight(pattern)
    val gapPattern = " ".repeat(patternWidth)
    val canvasRows = (1..height).map { Level ->
        val isOddLevel = Level % 2 != 0
        val gapPosition = if (isOddLevel) 0 else 1
        val rowWithGap = if (isOddLevel) {
            pattern + gapPattern.repeat((width - 1) / 2)
        } else {
            gapPattern.repeat((width - 1) / 2) + pattern
        }
        val adjustedRow = fillPatternRow(rowWithGap, width * patternWidth)
        adjustedRow.repeat(patternHeight)
    }
    return canvasRows.joinToString(newLineSymbol)
}

fun applyGenerator(pattern: String, generatorName: String, width: Int, height: Int): String  {
    val trimmedPattern = pattern.trimIndent()
    return when (generatorName) {
        "canvas" -> canvasGenerator(trimmedPattern, width, height)
        "canvasGaps" -> canvasWithGapsGenerator(trimmedPattern, width, height)
        else -> throw IllegalArgumentException("Unexpected generator name: $generatorName")
    }
}

