package jetbrains.kotlin.course.almost.done

fun trimPicture(picture: String): String {
    return picture.trimIndent().trimEnd()
}

fun applyBordersFilter(picture: String): String {
    val pictureWidth = getPictureWidth(picture)
    val borderLine = "$borderSymbol".repeat(pictureWidth + 4)
    val picturePadding = picture.lines().mapIndexed { index, line ->
        val pictureLength = pictureWidth - line.length
        val pictureLine = line + " ".repeat(pictureLength)
        if (index == 0) {
            if (index + 1 < picture.lines().size && picture.lines()[index + 1].startsWith(borderSymbol)) {
                "$pictureLine$separator$borderSymbol"
            } else {
                "$borderSymbol$separator$pictureLine$separator$borderSymbol"
            }
        } else {
            "$borderSymbol$separator$pictureLine$separator$borderSymbol"
        }
    }
    val pictureBorder = picturePadding.joinToString(newLineSymbol)
    return """
$borderLine
$pictureBorder
$borderLine
""".trimEnd()
}

fun applySquaredFilter(picture: String): String {
    val pictureWidth = getPictureWidth(picture)
    val maxLength = picture.lines().maxOfOrNull { it.length } ?: 0
    val squaredLines = mutableListOf<String>()

    for (line in picture.lines()) {
        val paddedLine = line.padEnd(maxLength, separator)
        squaredLines.add("$borderSymbol $paddedLine $borderSymbol")
    }

    val borderLine = "$borderSymbol".repeat(maxLength + 4)
    val squaredPicture = squaredLines.joinToString(newLineSymbol)

    return """
        |$borderLine
        |$squaredPicture
        |$borderLine
    """.trimMargin()
}

fun applyFilter(picture: String, filter: String): String {
    val trimmedPicture = trimPicture(picture)
    return when (filter) {
        "borders" -> applyBordersFilter(trimmedPicture)
        "squared" -> applySquaredFilter(trimmedPicture)
        else -> error("Learn how to write for fs")
    }
}

