// You will use this function later
fun safeReadLine(): String = readlnOrNull() ?: error("Your input is incorrect, sorry")

fun getPatternHeight(pattern: String): Int = pattern.lines().size

fun fillPatternRow(patternRow: String, patternWidth: Int): String =
    if (patternRow.length <= patternWidth) {
        patternRow + separator.toString().repeat(patternWidth - patternRow.length)
    } else {
        throw IllegalStateException("pattern row is too long")
    }

fun repeatHorizontally(pattern: String, n: Int, patternWidth: Int): String {
    val sb = StringBuilder()
    for (line in pattern.lines()) {
        sb.append(fillPatternRow(line, patternWidth).repeat(n)).append(newLineSymbol)
    }
    return sb.toString()
}

fun dropTopFromLine(line: String, width: Int, patternHeight: Int, patternWidth: Int): String =
    if (patternHeight > 1) line.drop(patternWidth * width + 1) else line

fun canvasGenerator(pattern: String, width: Int, height: Int): String {
    val patternHeight = getPatternHeight(pattern)
    val patternWidth = getPatternWidth(pattern)
    val sb = StringBuilder()
    for (line in 1..height) {
        val repeatedPattern = repeatHorizontally(pattern, width, patternWidth)
        sb.append(
            if (line == 1) repeatedPattern else dropTopFromLine(
                repeatedPattern,
                width,
                patternHeight,
                patternWidth
            )
        )
    }
    return sb.toString()
}

fun repeatHorizontallyWithGaps(pattern: String, n: Int, patternWidth: Int, firstIsBlank:Boolean):String{
    val sb = StringBuilder()
    val offset = if (firstIsBlank) 1 else 0
    for (line in pattern.lines()) {
        for (i in 1..n) {
            if (i % 2 == offset) {
                sb.append(" ".repeat(patternWidth))
            } else {
                sb.append(fillPatternRow(line, patternWidth))
            }
        }
        sb.append('\n')
    }
    return sb.toString()
}

fun canvasWithGapsGenerator(pattern: String, width: Int, height: Int):String{
    val patternHeight = getPatternHeight(pattern)
    val patternWidth = getPatternWidth(pattern)
    val sb = StringBuilder()
    for (line in 1..height) {
        val repeatedPattern = repeatHorizontallyWithGaps(pattern, width, patternWidth, line%2 == 0)
        sb.append(
            if (line == 1) repeatedPattern else dropTopFromLine(
                repeatedPattern,
                width,
                patternHeight,
                patternWidth
            )
        )
    }
    return sb.toString()
}

