                if (i % 2 != 0 || nisse % 2 != 1) {
                    output.append("$separator".repeat(getPatternWidth(pattern)))
                } else {
                    output.append(p + "$separator".repeat(getPatternWidth(pattern) - p.length))
                }
            }
            output.append(newLineSymbol)
        }
    }

    return output.toString()
}

