fun canvasWithGapsGenerator(pattern: String, width: Int, height: Int): String {
    val output = StringBuilder()
    // return repeatHorizontally(rhombus, 5, 10)

    if (getPatternHeight(pattern) != 1) {

        //output.append(width)
