package jetbrains.kotlin.course.mastermind.advanced

// You will use this function later
fun getGameRules(wordLength: Int, maxAttemptsCount: Int, secretExample: String) =
    "Welcome to the game! $newLineSymbol" +
            newLineSymbol +
            "Two people play this game: one chooses a word (a sequence of letters), " +
            "the other guesses it. In this version, the computer chooses the word: " +
            "a sequence of $wordLength letters (for example, $secretExample). " +
            "The user has several attempts to guess it (the max number is $maxAttemptsCount). " +
            "For each attempt, the number of complete matches (letter and position) " +
            "and partial matches (letter only) is reported. $newLineSymbol" +
            newLineSymbol +
            "For example, with $secretExample as the hidden word, the BCDF guess will " +
            "give 1 full match (C) and 1 partial match (B)."

fun generateSecret(wordLength: Int, alphabet: String): String =
    List(wordLength) { alphabet.random() }.joinToString(separator = "")

fun countAllMatches(secret: String, guess: String): Int =
    minOf(secret.filter{it in guess}.length, guess.filter{it in secret}.length)

fun countPartialMatches(secret: String, guess: String): Int =
    countAllMatches(secret, guess) - countExactMatches(secret, guess)

fun countExactMatches(secret: String, guess: String): Int =
    guess.filterIndexed { letter, string -> secret[letter] == string }.length

fun isComplete(secret: String, guess: String): Boolean =
    secret == guess

fun printRoundResults(secret: String, guess: String): Unit =
    println("Your guess has ${countExactMatches(secret, guess)} full matches and ${countPartialMatches(secret, guess)} partial matches.")

fun isWon(complete: Boolean, attempts: Int, maxAttemptsCount: Int): Boolean =
    complete && attempts <= maxAttemptsCount

fun isLost(complete: Boolean, attempts: Int, maxAttemptsCount: Int): Boolean =
    !complete && attempts > maxAttemptsCount

fun safeUserInput(wordLength: Int, alphabet: String): String {
    println("Please input your guess. It should be of length $wordLength, and each symbol should be from the alphabet: $alphabet.")

    var userInput = safeReadLine()
    var isSafeUserInput = isCorrectInput(safeReadLine(), wordLength, alphabet)

    while(!isSafeUserInput) {
        userInput = safeReadLine()
        isSafeUserInput = isCorrectInput(userInput, wordLength, alphabet)
    }

    return userInput
}

fun isCorrectInput(userInput: String, wordLength: Int, alphabet: String): Boolean {
    if (userInput.length != wordLength) {
        println("The length of your guess should be $wordLength characters! Try again!")
        return false
    }

    if (userInput.any { it !in alphabet }) {
        println("All symbols in your guess should be the $alphabet alphabet characters! Try again!")
        return false
    }

    return true
}

fun playGame(secret: String, wordLength: Int, maxAttemptsCount: Int, alphabet: String) {
    var guess = safeUserInput(wordLength, alphabet)
    var isCompleted = isComplete(secret, guess)
    var attemptsCount = 0

    while (!isCompleted) {
        printRoundResults(secret, guess)
        attemptsCount++

        if (isWon(isComplete(secret, guess), attemptsCount, maxAttemptsCount)) {
            println("Congratulations! You guessed it!")
            break
        }

        if (isLost(isComplete(secret, guess), attemptsCount, maxAttemptsCount)) {
            println("Sorry, you lost! :( My word is $secret")
            break
        }

        guess = safeUserInput(wordLength, alphabet)
        isCompleted = isComplete(secret, safeUserInput(wordLength, alphabet))
    }







//    do {
//        guess = safeUserInput(wordLength, alphabet)
//        printRoundResults(secret, guess)
//
//        attemptsCount++
//
//        if (isWon(isComplete(secret, guess), attemptsCount, maxAttemptsCount)) {
//            println("Congratulations! You guessed it!")
//            break
//        }
//
//        if (isLost(isComplete(secret, guess), attemptsCount, maxAttemptsCount)) {
//            println("Sorry, you lost! :( My word is $secret")
//            break
//        }
//    } while (!isComplete(secret, guess))
}

fun main() {
    val wordLength = 4
    val maxAttemptsCount = 3
    val alphabet = "ABCDEFG"

    println(getGameRules(wordLength, maxAttemptsCount, secretExample = "ACEB"))
    playGame(generateSecret(wordLength, alphabet), wordLength, maxAttemptsCount, alphabet)
}

