// You will use this function later
fun safeReadLine(): String = readlnOrNull() ?: error("Your input is incorrect, sorry")

fun getPatternHeight(pattern: String): Int = pattern.lines().count()

fun fillPatternRow(patternRow: String, patternWidth: Int): String {
    if (patternRow.length > patternWidth)
        throw IllegalStateException("Patternrow cannot be longer than the pattern width")

    val seperate = patternWidth - patternRow.length

    val seperateString = separator.toString().repeat(seperate)

    return "$patternRow$seperateString"
}

fun repeatHorizontally(pattern: String, n: Int, patternWidth: Int): String {
    val result = StringBuilder("")

    val patternline = pattern.lines()

    for (line in patternline) {

        result.appendLine(fillPatternRow(line, patternWidth).repeat(n))

    }

    return result.toString()
}

fun dropTopFromLine(line: String, width: Int, patternHeight: Int, patternWidth: Int): String {
    if (patternHeight <= 1)
        return line

    return line.drop(patternWidth * width + newLineSymbol.length)
}

fun canvasGenerator(pattern: String, width: Int, height: Int): String {
    val patternWidth = getPatternWidth(pattern)
    val patternHeight = getPatternHeight(pattern)

    // Repeat the pattern horizontally to match the canvas width
    val repeatedPattern = repeatHorizontally(pattern, width, patternWidth)

    // Initialize the canvas with the repeated pattern
    val canvas = StringBuilder(repeatedPattern)

    // Repeat the pattern vertically to match the canvas height
    for (i in 1 until height) {
        // Drop the top line from the repeated pattern if patternHeight is greater than 1
        val modifiedPattern = if (patternHeight > 1) {
            dropTopFromLine(repeatedPattern, width, patternHeight, patternWidth)
        } else {
            repeatedPattern
        }

        // Append the modified pattern to the canvas
        canvas.append(modifiedPattern)
    }

    return canvas.toString()
}

// I give up!
fun canvasWithGapsGenerator(pattern: String, width: Int, height: Int): String {
    val patternWidth = getPatternWidth(pattern)
    val patternHeight = getPatternHeight(pattern)

    val canvas = StringBuilder()

    for (i in 0 until height) {
        if (i % 2 == 0) {
            // Even row: append the pattern
            canvas.append(canvasGenerator(pattern, width, 1))
            canvas.append(newLineSymbol)
        } else {
            // Odd row: append gaps in place of every other character
            for (j in 0 until width) {
                if (j % 2 == 0) {
                    // Append a space for gap
                    canvas.append(" ".repeat(patternWidth))
                    canvas.append(newLineSymbol)
                } else {
                    // Append the pattern
                    canvas.append(pattern)
                    canvas.append(newLineSymbol)
                }
            }
        }
        // Append newline symbol after each row

    }

    // Remove the last newline symbol if present
    canvas.dropLast(newLineSymbol.length+1)

    return canvas.toString()
}


