fun trimPicture(picture: String) = picture.trimIndent()

fun applyBordersFilter(picture: String): String = makeBorders(makeBorders(picture, separator, false), borderSymbol)

fun makeBorders(picture: String, symbol: Char, horizontal: Boolean = true): String {
    val lines = picture.lines()
    val width = getPictureWidth(picture)
    val hBorder = symbol.toString().repeat(width + 2)
    val sb = StringBuilder()
    if (horizontal) sb.append(hBorder, "\n")
    sb.append(lines.joinToString("\n") { l -> symbol + l + symbol.toString().repeat(width - l.length + 1) })
    if (horizontal) sb.append("\n", hBorder)
    return sb.toString()
}

fun applySquaredFilter(picture: String): String {
    val withBorders = applyBordersFilter(picture)
    val hDouble = withBorders.lines().map { i -> i + i }.joinToString("\n")
    return hDouble.dropLastWhile { it == '#' } + hDouble
}

fun applyFilter(picture: String, filter: String): String {
    val trimmed = trimPicture(picture)
    return when (filter) {
        "borders" -> applyBordersFilter(trimmed)
        "squared" -> applySquaredFilter(trimmed)
        else -> error("Wrong filter name!")
    }
}

fun safeReadLine() = readlnOrNull() ?: error("Error while read line")

fun chooseFilter(): String {
    println("Please choose the filter: 'borders' or 'squared'")
    while (true) {
        when (val input = safeReadLine()) {
            "borders", "squared" -> return input
            else -> println("Please input 'borders' or 'squared'")
        }
    }
}

