// You will use this function later
fun getGameRules(wordLength: Int, maxAttemptsCount: Int, secretExample: String) =
    "Welcome to the game! $newLineSymbol" +
            newLineSymbol +
            "Two people play this game: one chooses a word (a sequence of letters), " +
            "the other guesses it. In this version, the computer chooses the word: " +
            "a sequence of $wordLength letters (for example, $secretExample). " +
            "The user has several attempts to guess it (the max number is $maxAttemptsCount). " +
            "For each attempt, the number of complete matches (letter and position) " +
            "and partial matches (letter only) is reported. $newLineSymbol" +
            newLineSymbol +
            "For example, with $secretExample as the hidden word, the BCDF guess will " +
            "give 1 full match (C) and 1 partial match (B)."

fun main() {
    val wordLength = 4
    val maxAttemptsCount = 3
    val secretExample = "ACEB"

    val hiddenWord = generateSecret()

    val gameRules = getGameRules(wordLength, maxAttemptsCount, secretExample)
    println(gameRules)

    playGame(hiddenWord, wordLength, maxAttemptsCount)
}
fun generateSecret() = "ABCD"
fun countPartialMatches(secret: String, guess: String): Int {
    var count = 0
    for (i in guess.indices) {
        if (guess[i] in secret && guess[i] != secret[i]) {
            count++
        }
    }
    return count
}
fun countExactMatches(secret: String, guess: String): Int {
    var count = 0
    for (i in guess.indices) {
        if (guess[i] == secret[i]) {
            count++
        }
    }
    return count
}
fun isComplete(secret: String, guess: String): Boolean {
    return secret == guess
}

fun playGame(secret: String, wordLength: Int, maxAttemptsCount: Int) {
    var completed = false
    var attemptsRemaining = maxAttemptsCount

    do {
        println("Please input your guess. It should be of length $wordLength.")
        val guess = safeReadLine() ?: continue

        if (guess.length != wordLength) {
            println("Invalid guess! Please enter a word of length $wordLength.")
            continue
        }

        completed = isComplete(secret, guess)

        attemptsRemaining--

        if (completed) {
            println("Congratulations! You guessed the word in $maxAttemptsCount attempts.")
        } else {
            val exactMatches = countExactMatches(secret, guess)
            val partialMatches = countPartialMatches(secret, guess)
            if (exactMatches > 0) {
                println("You have $exactMatches exact matches.")
            }
            if (partialMatches > 0) {
                println("You have $partialMatches partial matches.")
            }
            println("Attempts remaining: $attemptsRemaining")
            if (attemptsRemaining == 0) {
                println("Unfortunately, you ran out of attempts. The word was: $secret")
            }
        }
    } while (!completed && attemptsRemaining > 0)
}

