fun isComplete(secret: String, guess: String): Boolean {
    return secret == guess
}

fun playGame(secret: String, wordLength: Int, maxAttemptsCount: Int) {
    var completed = false
    var attemptsRemaining = maxAttemptsCount

    do {
        println("Please input your guess. It should be of length $wordLength.")
        val guess = safeReadLine() ?: continue

        // Check if the guess has the correct length
        if (guess.length != wordLength) {
            println("Invalid guess! Please enter a word of length $wordLength.")
            continue
        }

        // Check if the guess matches the secret word
        completed = isComplete(secret, guess)

        attemptsRemaining--

        // Provide feedback based on the guess
        if (completed) {
            println("Congratulations! You guessed the word in $attemptsRemaining attempts.")
        } else {
            val exactMatches = countExactMatches(secret, guess)
            val partialMatches = countPartialMatches(secret, guess)
            if (exactMatches > 0) {
                println("You have $exactMatches exact matches.")
            }
            if (partialMatches > 0) {
                println("You have $partialMatches partial matches.")
            }
            println("Attempts remaining: $attemptsRemaining")
            if (attemptsRemaining == 0) {
                println("Unfortunately, you ran out of attempts. The word was: $secret")
            }
        }
    } while (!completed && attemptsRemaining > 0)
}

